let data = JSON.parse(JSON.stringify(RAW));
data.forEach(r => { r._수정일 = null; r._수정ts = null; });
let changes = {};
let _allLogs = [];   // Firebase에서 로드된 전체 변경 로그

window._applyRemoteLog = function(logs) {
  _allLogs = logs;
  updateLog();
};
let currentEditNo = null;
let charts = {};

// ── 스냅샷 뷰 모드 상태 ──────────────────────────
let liveData = null;          // 라이브 데이터 백업 (스냅샷 진입 시)
let viewingWeek = null;       // 현재 보고 있는 주차 키 (null = 라이브)

function enterSnapshotMode(weekKey) {
  const snap = weeklyHistory[weekKey];
  if (!snap || !Array.isArray(snap.tasks)) {
    showToast('이 주차는 과제 스냅샷이 없습니다 (집계만 기록됨)');
    return;
  }
  // 라이브 데이터 백업 (최초 진입 시에만)
  if (viewingWeek === null) liveData = data;
  viewingWeek = weekKey;
  data = JSON.parse(JSON.stringify(snap.tasks));
  document.body.classList.add('snapshot-mode');
  const banner = document.getElementById('snapshotBanner');
  if (banner) {
    banner.style.display = 'flex';
    document.getElementById('snapshotBannerLabel').textContent =
      `${snap.label} (${snap.savedAt || ''})`;
  }
  highlightWeeklyNav(weekKey);
  populateTargetFilter(data);
  // 스냅샷 데이터는 과거 데이터이므로 '최근 수정' 필터 해제
  const recentFilter = document.getElementById('filterRecent');
  if (recentFilter) recentFilter.value = '';
  applyFilter();
  renderDashboard();
  renderSchedule();
  renderAgents();
}

function exitSnapshotMode() {
  if (viewingWeek === null) return;
  if (liveData) data = liveData;
  liveData = null;
  viewingWeek = null;
  document.body.classList.remove('snapshot-mode');
  const banner = document.getElementById('snapshotBanner');
  if (banner) banner.style.display = 'none';
  highlightWeeklyNav(null);
  populateTargetFilter(data);
  applyFilter();
  renderDashboard();
  renderSchedule();
  renderAgents();
}

function highlightWeeklyNav(weekKey) {
  document.querySelectorAll('#weeklyNav .tab').forEach(el => el.classList.remove('active'));
  if (weekKey === null) {
    const live = document.getElementById('weeklyNavLive');
    if (live) live.classList.add('active');
  } else {
    const el = document.querySelector(`#weeklyNav [data-week="${weekKey}"]`);
    if (el) el.classList.add('active');
  }
}

// ── 탭 전환 ──────────────────────────────
function switchTab(id, el) {
  document.querySelectorAll('.tab-content').forEach(t => t.classList.remove('active'));
  document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
  document.getElementById('tab-'+id).classList.add('active');
  el.classList.add('active');
  if (id==='dashboard') { renderDashboard(); loadWeeklyHistory(); }
  if (id==='schedule') renderSchedule();
  if (id==='agents') renderAgents();
  if (id==='tasklist') { updateTaskStickyOffset(); syncHeaderWidths(); requestAnimationFrame(syncHeaderWidths); }
}

// ── 차트 헬퍼 ────────────────────────────
function destroyChart(id) { if(charts[id]){charts[id].destroy();delete charts[id];} }

function renderDashboard() {
  const active = data.filter(d=>d.착수상태);
  const started = data.filter(d=>d.착수상태==='착수');
  const notStarted = data.filter(d=>d.착수상태==='미착수');
  const avg = active.length ? Math.round(active.reduce((s,d)=>s+d.진척률,0)/active.length*100) : 0;
  const done = data.filter(d=>d.진척률>=1.0 && d.착수상태==='착수');
  document.getElementById('kpi-started').textContent = started.length;
  document.getElementById('kpi-not').textContent = notStarted.length;
  document.getElementById('kpi-avg').textContent = avg+'%';
  document.getElementById('kpi-started-pct').textContent = Math.round(started.length/active.length*100)+'%';
  document.getElementById('kpi-done').textContent = done.length;
  document.getElementById('kpi-done-pct').textContent = active.length ? Math.round(done.length/active.length*100)+'%' : '0%';

  // 착수 현황 도넛
  destroyChart('chartStatus');
  charts['chartStatus'] = new Chart(document.getElementById('chartStatus'), {
    type:'doughnut',
    data:{labels:['착수','미착수'],datasets:[{data:[started.length,notStarted.length],backgroundColor:['#147B52','#E5E7EB'],borderWidth:0,hoverOffset:6}]},
    options:{responsive:true,maintainAspectRatio:false,cutout:'68%',plugins:{legend:{position:'bottom',labels:{usePointStyle:true,pointStyle:'circle',font:{family:"'Pretendard',sans-serif",size:12},color:'#475467',padding:14}}}}
  });

  // SHIFT 바
  const shiftMap = {};
  data.filter(d=>d.shift).forEach(d=>{
    const s = d.shift||'기타';
    if(!shiftMap[s]) shiftMap[s]={착수:0,미착수:0};
    if(d.착수상태==='착수') shiftMap[s].착수++;
    else if(d.착수상태==='미착수') shiftMap[s].미착수++;
  });
  destroyChart('chartShift');
  charts['chartShift'] = new Chart(document.getElementById('chartShift'), {
    type:'bar',
    data:{labels:Object.keys(shiftMap),datasets:[
      {label:'착수',data:Object.values(shiftMap).map(v=>v.착수),backgroundColor:'#147B52',borderRadius:6,maxBarThickness:32},
      {label:'미착수',data:Object.values(shiftMap).map(v=>v.미착수),backgroundColor:'#E5E7EB',borderRadius:6,maxBarThickness:32}
    ]},
    options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{position:'bottom',labels:{usePointStyle:true,pointStyle:'circle',font:{family:"'Pretendard',sans-serif",size:12},color:'#475467',padding:14}}},scales:{x:{stacked:true,grid:{display:false},ticks:{font:{family:"'Pretendard',sans-serif",size:11},color:'#98A2B3'}},y:{stacked:true,grid:{color:'#F3F4F6',drawBorder:false},ticks:{font:{family:"'Pretendard',sans-serif",size:11},color:'#98A2B3'}}}}
  });

  // 에이전트별 평균 진척률
  const agMap = {};
  data.filter(d=>d.에이전트).forEach(d=>{
    if(!agMap[d.에이전트]) agMap[d.에이전트]=[];
    agMap[d.에이전트].push(d.진척률);
  });
  const agLabels = Object.keys(agMap).map(k=>k.replace(/^[AB]-\d+\.\s*/,''));
  const agVals = Object.keys(agMap).map(k=>Math.round(agMap[k].reduce((s,v)=>s+v,0)/agMap[k].length*100));
  destroyChart('chartAgent');
  const agCount = agLabels.length;
  const agHeight = Math.max(280, agCount * 28 + 60);
  document.getElementById('chartAgentWrap').style.height = agHeight + 'px';
  charts['chartAgent'] = new Chart(document.getElementById('chartAgent'), {
    type:'bar',
    data:{labels:agLabels,datasets:[{label:'평균 진척률(%)',data:agVals,backgroundColor:'#147B52',borderRadius:6,maxBarThickness:18}]},
    options:{
      indexAxis:'y',responsive:true,maintainAspectRatio:false,
      plugins:{legend:{display:false},datalabels:{display:false}},
      layout:{padding:{right:10}},
      scales:{
        x:{max:100,grid:{color:'#F3F4F6',drawBorder:false},ticks:{font:{family:"'Pretendard',sans-serif",size:11},color:'#98A2B3'}},
        y:{grid:{display:false},ticks:{font:{family:"'Pretendard',sans-serif",size:11},color:'#475467',mirror:false},afterFit(scale){scale.width=200;}}
      }
    }
  });

  // 우선순위 × 착수상태
  const pMap = {상:{착수:0,미착수:0},중:{착수:0,미착수:0},하:{착수:0,미착수:0}};
  data.filter(d=>d.우선순위&&d.착수상태).forEach(d=>{
    if(pMap[d.우선순위]&&(d.착수상태==='착수'||d.착수상태==='미착수')) pMap[d.우선순위][d.착수상태]++;
  });
  destroyChart('chartPriority');
  charts['chartPriority'] = new Chart(document.getElementById('chartPriority'), {
    type:'bar',
    data:{labels:['상','중','하'],datasets:[
      {label:'착수',data:[pMap.상.착수,pMap.중.착수,pMap.하.착수],backgroundColor:'#147B52',borderRadius:6,maxBarThickness:36},
      {label:'미착수',data:[pMap.상.미착수,pMap.중.미착수,pMap.하.미착수],backgroundColor:'#E5E7EB',borderRadius:6,maxBarThickness:36}
    ]},
    options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{position:'bottom',labels:{usePointStyle:true,pointStyle:'circle',font:{family:"'Pretendard',sans-serif",size:12},color:'#475467',padding:14}}},scales:{x:{stacked:false,grid:{display:false},ticks:{font:{family:"'Pretendard',sans-serif",size:11},color:'#98A2B3'}},y:{stacked:false,grid:{color:'#F3F4F6',drawBorder:false},ticks:{font:{family:"'Pretendard',sans-serif",size:11},color:'#98A2B3'}}}}
  });
}

function renderSchedule() {
  const qMap = {};
  data.forEach(d=>{
    const q = normalizeTarget(d.목표완료);
    if (!q) return;
    if(!qMap[q]) qMap[q]={착수:0,미착수:0,items:[]};
    if(d.착수상태==='착수') qMap[q].착수++;
    else if(d.착수상태==='미착수') qMap[q].미착수++;
    qMap[q].items.push(d);
  });
  const qs = Object.keys(qMap).sort();
  // 분기별 착수율·평균 진척률 산출
  const startRates = qs.map(q=>{const d=qMap[q].착수+qMap[q].미착수; return d?Math.round(qMap[q].착수/d*100):0;});
  const avgProgs = qs.map(q=>{const t=qMap[q].items.length; return t?Math.round(qMap[q].items.reduce((s,it)=>s+(it.진척률||0),0)/t*100):0;});
  const maxVal = Math.max(1,...qs.map(q=>Math.max(qMap[q].착수,qMap[q].미착수)));

  // 막대 위에 착수율·진척률 배지를 직접 그리는 커스텀 플러그인 (datalabels 미사용)
  const roundRect=(c,x,y,w,h,r)=>{c.beginPath();c.moveTo(x+r,y);c.arcTo(x+w,y,x+w,y+h,r);c.arcTo(x+w,y+h,x,y+h,r);c.arcTo(x,y+h,x,y,r);c.arcTo(x,y,x+w,y,r);c.closePath();};
  const quarterRatePlugin = {
    id:'quarterRate',
    afterDatasetsDraw(chart){
      const ctx=chart.ctx, m0=chart.getDatasetMeta(0), m1=chart.getDatasetMeta(1);
      ctx.save();
      ctx.font="700 11px 'Pretendard',sans-serif";
      qs.forEach((q,i)=>{
        const b0=m0.data[i]; if(!b0) return;
        const b1=m1.data[i];
        const cx=b1?(b0.x+b1.x)/2:b0.x;
        const topY=Math.min(b0.y, b1?b1.y:b0.y);
        const sTxt=`착수 ${startRates[i]}%`, pTxt=`진척 ${avgProgs[i]}%`;
        const padX=9,gap=9,dot=7,dotGap=4,H=22;
        const sW=dot+dotGap+ctx.measureText(sTxt).width;
        const pW=dot+dotGap+ctx.measureText(pTxt).width;
        const W=padX+sW+gap+1+gap+pW+padX;
        let x=cx-W/2, y=topY-H-8;
        if(y<chart.chartArea.top+2) y=topY+6;   // 위 공간 부족 시 막대 상단 안쪽에
        // 배경 pill
        ctx.fillStyle='#ffffff'; ctx.strokeStyle='#E4E7EC'; ctx.lineWidth=1;
        ctx.shadowColor='rgba(16,24,40,.12)'; ctx.shadowBlur=6; ctx.shadowOffsetY=2;
        roundRect(ctx,x,y,W,H,11); ctx.fill();
        ctx.shadowColor='transparent'; ctx.stroke();
        // 내용
        const midY=y+H/2; let tx=x+padX;
        ctx.textBaseline='middle'; ctx.textAlign='left';
        ctx.fillStyle='#10B981'; ctx.beginPath(); ctx.arc(tx+dot/2,midY,dot/2,0,Math.PI*2); ctx.fill();
        tx+=dot+dotGap; ctx.fillStyle='#067647'; ctx.fillText(sTxt,tx,midY);
        tx+=ctx.measureText(sTxt).width+gap;
        ctx.strokeStyle='#EAECF0'; ctx.beginPath(); ctx.moveTo(tx,y+5); ctx.lineTo(tx,y+H-5); ctx.stroke();
        tx+=1+gap;
        ctx.fillStyle='#2E90FA'; ctx.beginPath(); ctx.arc(tx+dot/2,midY,dot/2,0,Math.PI*2); ctx.fill();
        tx+=dot+dotGap; ctx.fillStyle='#175CD3'; ctx.fillText(pTxt,tx,midY);
      });
      ctx.restore();
    }
  };

  destroyChart('chartQuarter');
  charts['chartQuarter'] = new Chart(document.getElementById('chartQuarter'), {
    type:'bar',
    data:{labels:qs,datasets:[
      {label:'착수',data:qs.map(q=>qMap[q].착수),backgroundColor:'#10B981',borderRadius:6,maxBarThickness:40},
      {label:'미착수',data:qs.map(q=>qMap[q].미착수),backgroundColor:'#E5E7EB',borderRadius:6,maxBarThickness:40}
    ]},
    options:{responsive:true,maintainAspectRatio:false,layout:{padding:{top:8}},plugins:{legend:{position:'bottom',labels:{usePointStyle:true,pointStyle:'circle',font:{family:"'Pretendard',sans-serif",size:12},color:'#475467',padding:14}},tooltip:{callbacks:{title(items){return qs[items[0].dataIndex];},footer(items){const i=items[0].dataIndex;return `착수율 ${startRates[i]}%  ·  평균 진척률 ${avgProgs[i]}%`;}}}},scales:{x:{grid:{display:false},ticks:{font:{family:"'Pretendard',sans-serif",size:11},color:'#98A2B3'}},y:{suggestedMax:Math.ceil(maxVal*1.25),grid:{color:'#F3F4F6',drawBorder:false},ticks:{font:{family:"'Pretendard',sans-serif",size:11},color:'#98A2B3'}}}},
    plugins:[quarterRatePlugin]
  });

  // 분기별 목록
  const listDiv = document.getElementById('quarterList');
  listDiv.innerHTML = qs.map((q,qi)=>`
    <div style="margin-bottom:18px;">
      <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:10px;">
        <span style="display:inline-flex;align-items:center;gap:8px;font-weight:700;color:#147B52;padding:6px 14px;background:#E9F7EF;border:1px solid #BFE8D0;border-radius:999px;font-size:13px;letter-spacing:0;">${q} <span style="color:#1B8F61;">·</span> <span style="color:#475467;font-weight:600;">${qMap[q].items.length}건</span></span>
        <span style="font-size:12px;font-weight:600;color:#475467;padding:5px 11px;background:#F2F4F7;border:1px solid #EAECF0;border-radius:999px;">착수율 <span style="color:#147B52;font-weight:700;">${startRates[qi]}%</span></span>
        <span style="font-size:12px;font-weight:600;color:#475467;padding:5px 11px;background:#F2F4F7;border:1px solid #EAECF0;border-radius:999px;">평균 진척률 <span style="color:#147B52;font-weight:700;">${avgProgs[qi]}%</span></span>
      </div>
      <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:10px;">
        ${qMap[q].items.map(it=>{const pct=Math.round((it.진척률||0)*100);return `
          <div style="background:#fff;border:1px solid #EAECF0;border-radius:12px;padding:12px 14px;font-size:13px;cursor:pointer;transition:all .15s;" onclick="goToTask(${it.no})" onmouseover="this.style.boxShadow='0 4px 12px rgba(20,123,82,.12)';this.style.borderColor='#BFE8D0';this.style.transform='translateY(-1px)'" onmouseout="this.style.boxShadow='';this.style.borderColor='#EAECF0';this.style.transform=''">
            <div style="display:flex;align-items:center;gap:6px;margin-bottom:6px;">
              <span style="color:#667085;font-weight:600;">No.${it.no}</span>
              <span class="${it.착수상태==='착수'?'badge-착수':'badge-미착수'}">${it.착수상태||'-'}</span>
            </div>
            <div style="color:#101828;font-size:14px;font-weight:500;line-height:1.5;">${it.태스크.split('\n')[0]}</div>
            <div style="margin-top:6px;color:#475467;">${it.담당자||'-'}</div>
            <div style="margin-top:8px;">
              <div style="display:flex;justify-content:space-between;font-size:11px;color:#667085;margin-bottom:3px;"><span>진척률</span><span style="color:#147B52;font-weight:700;">${pct}%</span></div>
              <div style="height:6px;background:#EEF2F0;border-radius:999px;overflow:hidden;"><div style="height:100%;width:${pct}%;background:#147B52;border-radius:999px;"></div></div>
            </div>
            <div style="margin-top:8px;color:#147B52;font-size:11px;font-weight:600;letter-spacing:0;">→ 과제목록에서 보기</div>
          </div>`;}).join('')}
      </div>
    </div>`).join('');
}

